-- 2026-06-25: shoulder_phf_orif — фазы «Путь» + структурированные критерии перехода.
-- Протокол: остеосинтез (ORIF) перелома проксимального отдела плечевой кости — пластина/винты.
--
-- Источник: proto_shoulder_phf_orif.json (suggested_program_type_code='shoulder_phf_orif',
-- anchor='time_and_criterion', 6 фаз 0..5). Сугубо послеоперационный путь (ORIF и есть хирургия).
-- Фаза 0 (prehab) — ДО операции (при остром переломе сводится к подготовке, не к тренировкам);
-- фазы 1–5 — после.
--
-- Защитная ось: бережём фиксацию перелома и костное СРАЩЕНИЕ. Ключевой gate-критерий —
-- РЕНТГЕНОЛОГИЧЕСКАЯ КОНСОЛИДАЦИЯ (мостовидная мозоль, нет потери репозиции): появляется на переходе
-- ф2→ф3 (активная мобилизация) и ОБЯЗАТЕЛЕН ф3→ф4 (перед прогрессивным укреплением). Раннее — никаких
-- активных движений плечом и изолированной работы манжеты (до ~8 нед, чтобы не скомпрометировать
-- фиксацию), запрет осевой/весовой нагрузки на руку, ранний поворот руки наружу ограничен (~30–45°).
-- Темп индивидуализирует хирург по интраоперационной стабильности фиксации; при расхождении школ
-- по срокам выбирается более консервативный вариант со сверкой с хирургом.
--
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона PROM/AROM/ER/IR — раскрыт словами:
-- «пассивный подъём руки», «поворот руки наружу», «осевая нагрузка на руку» и т.п.).
-- Vadim калибрует через AdminContent после деплоя.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев (ТЗ §2.3): авто-проверяемо сегодня только боль ВАШ → criterion_type
-- 'measurement' (measurement_type='vas_score', source='pain'). У ЭТОГО протокола measurement-критериев
-- НЕТ: в источнике отдельных gate-критериев по боли/ВАШ нет — боль фигурирует только как
-- self_report-вопрос («контролируется ли боль настолько, что можете выполнять упражнения»).
-- Все числовые пороги (градусы объёма движений, недели от операции, сила в %) и рентген система не
-- хранит → 'instructor_check' с порогом в ТЕКСТЕ label (куратор/хирург вводит очно). Качественное
-- да/нет от пациента → 'self_report'.
--
-- Фаза 0 (prehab) — пустой structured-набор, в WITH НЕ включена (criteria_next текстом).
-- Терминальная фаза 5 — в источнике transition_criteria НЕ пустой («ориентиры готовности» к
-- возврату к спорту: сила ≥80%, полный безболезненный объём, низкий QuickDASH) → критерии включены.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_phf_orif (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'shoulder_phf_orif', 0,
    'Подготовка к операции',
    'До операции',
    '',
    'Подготовка к остеосинтезу перелома плеча. При свежем переломе операцию обычно делают в ближайшие дни, поэтому сейчас главное — не тренировки, а подготовка: унять боль покоем, обеспечить руке надёжную поддержку и понять, как будет устроено восстановление. До операции врач проверит, в порядке ли нервы и сосуды руки.',
    '["Обезболивание и покой руки","Разобраться в предстоящем режиме: косыночная повязка (слинг), ранние упражнения для кисти и локтя","Дооперационная проверка нервов и сосудов руки (это делает врач)","Сформировать реалистичные ожидания от восстановления"]',
    '["Не двигать оперируемым плечом активно","Не нагружать руку","Не садиться за руль"]',
    '["Операция выполнена, рана состоятельна, нервы и сосуды кисти в порядке (проверка врачом)","Понятно, как носить косыночную повязку и какие упражнения для кисти и локтя выполнять"]',
    'sprout', '#10B981', '#EDFAF5',
    'Унять боль, поддержать руку и понять восстановление',
    '["Иммобилизация руки в косыночной повязке (слинге) с мягким валиком под мышкой для комфорта","Активные движения пальцами и кистью","Общая активность: ходьба"]',
    '["Покой и поддержка руки должны заметно уменьшать боль","Острая нарастающая боль — повод показаться врачу"]',
    '["Держите руку в косыночной повязке и старайтесь её не нагружать","Двигайте пальцами и кистью, чтобы не было застоя","Подготовьте дом: вещи первой необходимости — на уровне пояса"]',
    '["Нарастающее онемение или слабость в руке либо кисти — возможно повреждение нерва","Бледная, холодная кисть, ослабление пульса — возможно повреждение сосуда","Резко нарастающий отёк — срочно к врачу"]',
    '[{"q":"Зачем что-то готовить, если впереди операция?","a":"При свежем переломе главное сейчас — покой и надёжная поддержка руки, чтобы унять боль. А понимание режима (косыночная повязка, упражнения для кисти) заметно облегчит первые недели после операции."},{"q":"Что самое важное на этом этапе?","a":"Не нагружать и не двигать активно больным плечом, держать руку в косыночной повязке и сразу сообщать врачу о нарастающем онемении, похолодании кисти или резком отёке — это сигналы со стороны нервов и сосудов."}]'
),
(
    'shoulder_phf_orif', 1,
    'Ранняя защита и пассивные движения',
    'Первые 0–3 недели',
    '0-3',
    'Самый ответственный этап. Перелом скреплён пластиной и винтами и только начинает срастаться, поэтому плечо пока работать само не должно — руку двигает либо ваша здоровая рука, либо куратор. Задача — защитить фиксацию, унять боль и отёк и при этом не дать суставу «застыть». Важно: пассивная разработка — это не растяжка через боль.',
    '["Защитить фиксацию и помочь костному сращению","Держать под контролем боль и отёк","Вернуть пассивный объём движений плеча (двигаем за вас)","Сохранить подвижность локтя, запястья и кисти"]',
    '["Любые активные движения плечом запрещены — рукой пока не двигаете сами","Изолированно напрягать мышцы вращательной манжеты нельзя (примерно до 8 недель — это может сместить фиксацию)","Нельзя отводить руку в сторону выше 90 градусов","Нельзя поднимать предметы больной рукой (даже лёгкие — ориентир до 0,5 кг)","Нельзя опираться весом тела на руку (осевая нагрузка)","Нельзя садиться за руль","Поворот руки наружу — не больше предела, заданного хирургом (обычно около 30–45 градусов)","Избегать движений в болезненный диапазон: пассивная разработка — не растяжка"]',
    '["Пассивный подъём руки вперёд не менее 140 градусов","Пассивный поворот руки наружу не менее 40 градусов","Пассивное отведение руки в сторону не менее 90 градусов","С операции прошло не менее 3 недель (точный срок задаёт хирург)","Полный активный объём движений в локте, боль и отёк под контролем"]',
