    'zap', '#8B5CF6', '#F4F0FD',
    'Возврат силы и выносливости плеча',
    '["Прогрессия от изометрии к ленте и лёгким свободным весам (ориентир 0,5–2,5 кг, 8–12 повторений, 2–3 подхода)","Упражнения для манжеты, дельтовидной и стабилизаторов лопатки (для манжеты — не чаще 3 раз в неделю, чтобы не вызвать раздражение сухожилий)","Упражнения на удержание стабильного положения плеча, отжимания по прогрессии (стена → стол → колени → планка)","Растяжка в конце амплитуды, особенно задней части капсулы сустава"]',
    '["Прогрессируйте по переносимости, без стойкой боли","Мышечная усталость допустима, суставная боль — сигнал сбавить","Боль после нагрузки не должна накапливаться день ото дня"]',
    '["Чередуйте силовые и восстановительные дни","Прибавляйте вес постепенно, особенно при остеопорозе","Качество движения важнее веса"]',
    '["Возобновление боли, отёка или ограничения движений","Ощущение нестабильности в плече","Новые онемение или слабость в руке"]',
    '[{"q":"Когда я снова стану сильным, как раньше?","a":"Сила возвращается постепенно, в течение месяцев регулярной работы, и зависит от тяжести перелома, качества кости и возраста. Ориентир готовности к спорту — около 80% силы здоровой руки и полный безболезненный объём движений."},{"q":"Почему манжету не качать каждый день?","a":"Сухожилия вращательной манжеты при слишком частой нагрузке легко раздражаются. Поэтому такие упражнения делают не чаще 3 раз в неделю, давая тканям восстановиться между занятиями."}]'
),
(
    'shoulder_phf_orif', 5,
    'Возврат к функции и спорту',
    'От 4,5 месяцев',
    '18-26',
    'Финальный этап. Плечо сильное и подвижное — теперь готовим его к вашим реальным задачам: спорту, тяжёлой физической работе, высокой нагрузке с большой амплитудой. Решение о возврате к спорту индивидуальное; нагрузку наращиваем по готовности, без спешки.',
    '["Вернуться к спорту, тяжёлой физической работе и нагрузке с большой амплитудой","Полностью восстановить силу и чувство положения руки в пространстве"]',
    '["Нельзя садиться за руль, пока рука в повязке и нет уверенного контроля над рулём","К активному спорту и хобби — только после восстановления полного объёма движений и силы","Нагрузку наращивать постепенно"]',
    '["Сила оперированной руки не менее 80% от здоровой (ориентир готовности к спорту)","Полный безболезненный активный объём движений","Низкий балл по опроснику пациента (ориентир готовности, оценка куратора)"]',
    'trophy', '#EC4899', '#FFF9E6',
    'Подготовка плеча к спорту и нагрузкам',
    '["Эксцентрические упражнения (с акцентом на уступающую фазу)","Прыжково-бросковые упражнения, например броски утяжелённого мяча","Тренировка чувства положения руки (упражнения на нестабильной опоре)","Специальная программа под ваш вид спорта и постепенный возврат к нему"]',
    '["Боль при возврате к нагрузке, отёк или потеря объёма движений — повод пересмотреть программу","Прислушивайтесь к плечу на следующий день после нагрузки"]',
    '["Полноценная разминка перед каждой нагрузкой","Наращивайте спортивную нагрузку постепенно, по готовности","Сохраняйте поддерживающие упражнения для плеча"]',
    '["Боль при возврате к нагрузке","Отёк плеча","Потеря достигнутого объёма движений — требуют пересмотра программы"]',
    '[{"q":"Когда можно вернуться к спорту?","a":"Решение индивидуальное. Ориентиры готовности — около 80% силы здоровой руки, полный безболезненный объём движений и достаточный срок с операции (поздний этап обычно начинается с ~4,5 месяцев). Темп возврата согласуйте с куратором."},{"q":"Нужно ли продолжать упражнения после возврата к нагрузкам?","a":"Да. Поддерживающая программа сохраняет силу и подвижность плеча и снижает риск повторных проблем. Это полезная привычка надолго."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_phf_orif
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) — без structured-критериев. Фазы 1–5 (терминальная 5 несёт критерии готовности).
--    measurement (боль ВАШ vas_score+pain) В ЭТОМ ПРОТОКОЛЕ НЕТ — боль только как self_report.
--    Числа (градусы, недели, %) и рентген → instructor_check (порог в тексте label).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (ранняя защита → ассистированные и первые активные движения)
  (1, 'passive_flexion_140_p1',  'Пассивный подъём руки вперёд не менее 140°',                                              'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_40_p1',        'Пассивный поворот руки наружу не менее 40°',                                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'passive_abduction_90_p1', 'Пассивное отведение руки в сторону не менее 90°',                                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'weeks_since_op_3_p1',     'С операции прошло не менее 3 недель (точный срок задаёт хирург)',                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'pain_allows_exercise_p1', 'Боль под контролем настолько, что получается выполнять упражнения',                       'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль под контролем настолько, что вы можете выполнять упражнения?', 'Лёгкий дискомфорт допустим, резкая боль — нет', 50::smallint, TRUE),
  (1, 'elbow_rom_pain_ok_p1',    'Полный активный объём движений в локте, боль и отёк под контролем (оценка куратора)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (ассистированные движения → активные движения и начальное укрепление)
  (2, 'full_passive_rom_p2',     'Достигнут полный пассивный объём движений плеча (подъём руки в пределах нормы для вас)',   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'full_elbow_rom_p2',       'Полный активный объём движений в локте',                                                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'isometrics_tolerated_p2', 'Хорошо переносятся изометрические упражнения плеча и силовые упражнения локтя без боли (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, FALSE),
  (2, 'xray_union_signs_p2',     'Рентген подтверждает признаки сращения (мостовидная мозоль, нет потери репозиции) — оценка хирурга, допуск к активной мобилизации', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'lift_arm_supine_p2',      'Получается поднять руку лёжа на спине без помощи здоровой руки',                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается поднять руку лёжа на спине без помощи здоровой руки?', 'Оцените активный подъём без поддержки', 50::smallint, FALSE),

  -- Фаза 3 → Фаза 4 (активные движения и начальное укрепление → прогрессивное укрепление)
  (3, 'full_active_rom_p3',      'Полный активный объём движений плеча с правильной техникой',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'xray_union_confirmed_p3', 'Рентген подтверждает сращение перелома — обязательный допуск к прогрессивному укреплению (оценка хирурга)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'no_pain_compensation_p3', 'Силовые упражнения без боли и без компенсаций, например «вздёргивания» плеча (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'adl_with_arm_p3',         'Обычные бытовые дела даются оперированной рукой',                                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Справляетесь ли вы с обычными бытовыми делами оперированной рукой?', 'Например, одеться, поесть, дотянуться до полки на уровне плеча', 40::smallint, TRUE),

  -- Фаза 4 → Фаза 5 (прогрессивное укрепление → возврат к функции и спорту)
  (4, 'strength_80_pct_p4',      'Сила оперированной руки не менее 80% от здоровой (по динамометрии)',                      'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'full_painfree_arom_p4',   'Полный безболезненный активный объём движений',                                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'low_disability_score_p4', 'Низкий уровень бытовых ограничений по опроснику пациента (оценка куратора)',              'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (4, 'confident_return_p4',     'Чувствуете уверенность для возврата к спорту или тяжёлой нагрузке',                       'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Чувствуете ли вы себя уверенно для возврата к спорту или тяжёлой нагрузке?', 'Оцените по самочувствию плеча при нагрузке', 40::smallint, TRUE),

  -- Фаза 5 (терминальная) — ориентиры готовности к возврату к спорту
  (5, 'strength_80_pct_p5',      'Сила оперированной руки не менее 80% от здоровой (ориентир готовности к спорту)',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (5, 'full_painfree_arom_p5',   'Полный безболезненный активный объём движений (ориентир готовности к спорту)',            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (5, 'low_disability_score_p5', 'Низкий балл по опроснику пациента (ориентир готовности, оценка куратора)',                'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_phf_orif' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
